declare i8 @llvm.smax.i8(i8, i8) #0

define i8 @sub_smax0_sub_commute(i8 %x, i8 %y) {
  %sub = sub nsw i8 %x, %y
  %m = call i8 @llvm.smax.i8(i8 %sub, i8 0)
  %r = sub i8 %m, %x
  ret i8 %r
}

